30	static bool match_ids(RTLIL::IdString id, const std::string &pattern)
31	{
32		if (id == pattern)
33			return true;
34	
35		const char *id_c = id.c_str();
36		const char *pat_c = pattern.c_str();
37		size_t id_size = strlen(id_c);
38		size_t pat_size = pattern.size();
39	
40		if (*id_c == '\\' && id_size == 1 + pat_size && memcmp(id_c + 1, pat_c, pat_size) == 0)
41			return true;
42		if (patmatch(pat_c, id_c))
43			return true;
44		if (*id_c == '\\' && patmatch(pat_c, id_c + 1))
45			return true;
46		if (*id_c == '$' && *pat_c == '$') {
47			const char *q = strrchr(id_c, '$');
48			if (pattern == q)
49				return true;
50		}
51		return false;
52	}
